643   MatrixTy getMatrix(Value *MatrixVal, const ShapeInfo &SI,
644                      IRBuilder<> &Builder) {
645     FixedVectorType *VType = cast<FixedVectorType>(MatrixVal->getType());
646     assert(VType->getNumElements() == SI.NumRows * SI.NumColumns &&
647            "The vector size must match the number of matrix elements");
648 
649     // Check if we lowered MatrixVal using shape information. In that case,
650     // return the existing matrix, if it matches the requested shape
651     // information. If there is a mis-match, embed the result in a flat
652     // vector and split it later.
653     auto Found = Inst2ColumnMatrix.find(MatrixVal);
654     if (Found != Inst2ColumnMatrix.end()) {
655       MatrixTy &M = Found->second;
656       // Return the found matrix, if its shape matches the requested shape
657       // information
658       if (SI.NumRows == M.getNumRows() && SI.NumColumns == M.getNumColumns())
659         return M;
660 
661       MatrixVal = M.embedInVector(Builder);
662     }
663 
664     // Otherwise split MatrixVal.
