753   /// Propagate the shape information of instructions to their users.
754   /// The work list contains instructions for which we can compute the shape,
755   /// either based on the information provided by matrix intrinsics or known
756   /// shapes of operands.
757   SmallVector<Instruction *, 32>
758   propagateShapeForward(SmallVectorImpl<Instruction *> &WorkList) {
759     SmallVector<Instruction *, 32> NewWorkList;
760     // Pop an element for which we guaranteed to have at least one of the
761     // operand shapes.  Add the shape for this and then add users to the work
762     // list.
763     LLVM_DEBUG(dbgs() << "Forward-propagate shapes:\n");
764     while (!WorkList.empty()) {
765       Instruction *Inst = WorkList.pop_back_val();
766 
767       // New entry, set the value and insert operands
768       bool Propagate = false;
769       if (auto SI = computeShapeInfoForInst(Inst, ShapeMap))
770         Propagate = setShapeInfo(Inst, *SI);
771 
772       if (Propagate) {
773         NewWorkList.push_back(Inst);
774         for (auto *User : Inst->users())
775           if (ShapeMap.count(User) == 0)
776             WorkList.push_back(cast<Instruction>(User));
777       }
778     }
779 
780     return NewWorkList;
781   }
