783   /// Propagate the shape to operands of instructions with shape information.
784   /// \p Worklist contains the instruction for which we already know the shape.
785   SmallVector<Instruction *, 32>
786   propagateShapeBackward(SmallVectorImpl<Instruction *> &WorkList) {
787     SmallVector<Instruction *, 32> NewWorkList;
788 
789     auto pushInstruction = [](Value *V,
790                               SmallVectorImpl<Instruction *> &WorkList) {
791       Instruction *I = dyn_cast<Instruction>(V);
792       if (I)
793         WorkList.push_back(I);
794     };
795     // Pop an element with known shape.  Traverse the operands, if their shape
796     // derives from the result shape and is unknown, add it and add them to the
797     // worklist.
798     LLVM_DEBUG(dbgs() << "Backward-propagate shapes:\n");
799     while (!WorkList.empty()) {
800       Value *V = WorkList.pop_back_val();
801 
802       size_t BeforeProcessingV = WorkList.size();
803       if (!isa<Instruction>(V))
804         continue;
805 
806       Value *MatrixA;
807       Value *MatrixB;
808       Value *M;
809       Value *N;
810       Value *K;
811       if (match(V, m_Intrinsic<Intrinsic::matrix_multiply>(
812                        m_Value(MatrixA), m_Value(MatrixB), m_Value(M),
813                        m_Value(N), m_Value(K)))) {
814         if (setShapeInfo(MatrixA, {M, N}))
815           pushInstruction(MatrixA, WorkList);
816 
817         if (setShapeInfo(MatrixB, {N, K}))
818           pushInstruction(MatrixB, WorkList);
819 
820       } else if (match(V, m_Intrinsic<Intrinsic::matrix_transpose>(
821                               m_Value(MatrixA), m_Value(M), m_Value(N)))) {
822         // Flip dimensions.
823         if (setShapeInfo(MatrixA, {M, N}))
824           pushInstruction(MatrixA, WorkList);
825       } else if (match(V, m_Intrinsic<Intrinsic::matrix_column_major_store>(
826                               m_Value(MatrixA), m_Value(), m_Value(), m_Value(),
827                               m_Value(M), m_Value(N)))) {
828         if (setShapeInfo(MatrixA, {M, N})) {
829           pushInstruction(MatrixA, WorkList);
830         }
831       } else if (isa<LoadInst>(V) ||
832                  match(V, m_Intrinsic<Intrinsic::matrix_column_major_load>())) {
833         // Nothing to do, no matrix input.
834       } else if (isa<StoreInst>(V)) {
835         // Nothing to do.  We forward-propagated to this so we would just
836         // backward propagate to an instruction with an already known shape.
837       } else if (isShapePreserving(V)) {
838         auto ShapedOps = getShapedOperandsForInst(cast<Instruction>(V));
839         // Propagate to all operands.
840         ShapeInfo Shape = ShapeMap[V];
841         for (Use &U : ShapedOps) {
842           if (setShapeInfo(U.get(), Shape))
843             pushInstruction(U.get(), WorkList);
844         }
845       }
846       // After we discovered new shape info for new instructions in the
847       // worklist, we use their users as seeds for the next round of forward
848       // propagation.
849       for (size_t I = BeforeProcessingV; I != WorkList.size(); I++)
850         for (User *U : WorkList[I]->users())
851           if (isa<Instruction>(U) && V != U)
852             NewWorkList.push_back(cast<Instruction>(U));
853     }
854     return NewWorkList;
855   }
