620   /// Estimate the number of native vector operations for a multiply of matrices
621   /// with dimensions \p R x \p M and \p M x \p C. Native ops are computed as
622   /// ceil(ElementCount * ElementBits / RegisterBits).
623   ///
624   /// Native vector ops per operation type (VF = native vector elements):
625   ///   FMAs:    C * ceil(R/VF) * M (one FMA per VF output elements)
626   ///   A loads: ceil(R/VF) * M (A has M columns, ceil(R/VF) native loads each)
627   ///   B loads: ceil(M/VF) * C (B has C columns, ceil(M/VF) native loads each)
628   ///   Stores:  C * ceil(R/VF) (one store per VF output elements)
629   unsigned getNumNativeVectorOps(Type *EltType, unsigned R, unsigned M,
630                                  unsigned C) {
631     unsigned NumFMAs = C * getNumOps(EltType, R) * M;
632     unsigned NumALoads = getNumOps(EltType, R) * M;
633     unsigned NumBLoads = getNumOps(EltType, M) * C;
634     unsigned NumStores = getNumOps(EltType, R) * C;
635     return NumFMAs + NumALoads + NumBLoads + NumStores;
