253 static bool isShapePreserving(Value *V) {
254   Instruction *I = dyn_cast<Instruction>(V);
255   if (!I)
256     return true;
257 
258   if (isa<SelectInst>(I))
259     return true;
260 
261   if (I->isBinaryOp())
262     return true;
263 
264   if (auto *Cast = dyn_cast<CastInst>(V)) {
265     switch (Cast->getOpcode()) {
266     case llvm::Instruction::Trunc:
267     case llvm::Instruction::ZExt:
268     case llvm::Instruction::SExt:
269     case llvm::Instruction::FPToUI:
270     case llvm::Instruction::FPToSI:
271     case llvm::Instruction::UIToFP:
272     case llvm::Instruction::SIToFP:
273     case llvm::Instruction::FPTrunc:
274     case llvm::Instruction::FPExt:
275       return true;
276     case llvm::Instruction::AddrSpaceCast:
277     case CastInst::PtrToAddr:
278     case CastInst::PtrToInt:
279     case CastInst::IntToPtr:
280       return false;
281     case CastInst::BitCast: {
282       if (auto *SrcVTy = dyn_cast<FixedVectorType>(Cast->getSrcTy()))
283         if (auto *DestVTy = dyn_cast<FixedVectorType>(Cast->getDestTy()))
284           return SrcVTy->getNumElements() == DestVTy->getNumElements();
285       return false;
286     }
287     case llvm::Instruction::CastOpsEnd:
288       llvm_unreachable("not an actual cast op");
289     }
290     llvm_unreachable("unhandled cast opcode");
291   }
292 
293   if (auto *II = dyn_cast<IntrinsicInst>(V))
294     switch (II->getIntrinsicID()) {
295     case Intrinsic::abs:
296     case Intrinsic::fabs:
297       return true;
298     default:
299       return false;
300     }
301 
302   switch (I->getOpcode()) {
303   case Instruction::PHI:
304   case Instruction::FNeg:
305     return true;
306   default:
307     return false;
308   }
309 }
