321 /// Return the ShapeInfo for the result of \p I, it it can be determined.
322 static std::optional<ShapeInfo>
323 computeShapeInfoForInst(Instruction *I,
324                         const DenseMap<Value *, ShapeInfo> &ShapeMap) {
325   Value *M;
326   Value *N;
327   Value *K;
328   if (match(I, m_Intrinsic<Intrinsic::matrix_multiply>(
329                    m_Value(), m_Value(), m_Value(M), m_Value(N), m_Value(K))))
330     return ShapeInfo(M, K);
331   if (match(I, m_Intrinsic<Intrinsic::matrix_transpose>(m_Value(), m_Value(M),
332                                                         m_Value(N)))) {
333     // Flip dimensions.
334     return ShapeInfo(N, M);
335   }
336   if (match(I, m_Intrinsic<Intrinsic::matrix_column_major_store>(
337                    m_Value(), m_Value(), m_Value(), m_Value(), m_Value(M),
338                    m_Value(N))))
339     return ShapeInfo(N, M);
340   if (match(I, m_Intrinsic<Intrinsic::matrix_column_major_load>(
341                    m_Value(), m_Value(), m_Value(), m_Value(M), m_Value(N))))
342     return ShapeInfo(M, N);
343   Value *MatrixA;
344   if (match(I, m_Store(m_Value(MatrixA), m_Value()))) {
345     auto OpShape = ShapeMap.find(MatrixA);
346     if (OpShape != ShapeMap.end())
347       return OpShape->second;
348   }
349 
350   if (isShapePreserving(I)) {
351     auto ShapedOps = getShapedOperandsForInst(I);
352     // Find the first operand that has a known shape and use that.
353     for (auto &Op : ShapedOps) {
354       auto OpShape = ShapeMap.find(Op.get());
355       if (OpShape != ShapeMap.end())
356         return OpShape->second;
357     }
358   }
359   return std::nullopt;
360 }
