364 /// LowerMatrixIntrinsics contains the methods used to lower matrix intrinsics.
365 ///
366 /// Currently, the lowering for each matrix intrinsic is done as follows:
367 /// 1. Propagate the shape information from intrinsics to connected
368 /// instructions.
369 /// 2. Lower instructions with shape information (assuming column-major layout).
370 ///  The lowering works similarly using row-major layout.
371 ///  2.1. Get column vectors for each argument. If we already lowered the
372 ///       definition of an argument, use the produced column vectors directly.
373 ///       If not, split the operand vector containing an embedded matrix into
374 ///       a set of column vectors,
375 ///  2.2. Lower the instruction in terms of column major operations, which
376 ///       yields a set of column vectors containing result matrix. Note that we
377 ///       lower all instructions that have shape information. Besides the
378 ///       intrinsics, this includes stores for example.
379 ///  2.3. Update uses of the lowered instruction. If we have shape information
380 ///       for a user, there is nothing to do, as we will look up the result
381 ///       column matrix when lowering the user. For other uses, we embed the
382 ///       result matrix in a flat vector and update the use.
383 ///  2.4. Cache the result column matrix for the instruction we lowered
384 /// 3. After we lowered all instructions in a function, remove the now
385 ///    obsolete instructions.
386 ///
387 class LowerMatrixIntrinsics {
388   Function &Func;
389   const DataLayout &DL;
390   const TargetTransformInfo &TTI;
391   FunctionAnalysisManager *AM;
392   AliasAnalysis *AA = nullptr;
393   DominatorTree *DT = nullptr;
394   LoopInfo *LI = nullptr;
395   OptimizationRemarkEmitter *ORE = nullptr;
396 
397   /// Contains estimates of the number of operations (loads, stores, compute)
398   /// required to lower a matrix operation.
399   struct OpInfoTy {
400     /// Number of stores emitted to generate this matrix.
401     unsigned NumStores = 0;
402     /// Number of loads emitted to generate this matrix.
403     unsigned NumLoads = 0;
404     /// Number of compute operations emitted to generate this matrix.
405     unsigned NumComputeOps = 0;
406     /// Most of the time transposes can be fused with matrix multiplies or can
407     /// be folded away via algebraic simplifications.  This is the number of
408     /// transposes that we failed to make "free" via such optimizations.
409     unsigned NumExposedTransposes = 0;
410 
411     OpInfoTy &operator+=(const OpInfoTy &RHS) {
412       NumStores += RHS.NumStores;
413       NumLoads += RHS.NumLoads;
414       NumComputeOps += RHS.NumComputeOps;
415       NumExposedTransposes += RHS.NumExposedTransposes;
416       return *this;
417     }
418   };
