420   /// Wrapper class representing a matrix as a set of vectors, either in row or
421   /// column major layout. All vectors must have the same vector type.
422   class MatrixTy {
423     SmallVector<Value *, 16> Vectors;
424 
425     OpInfoTy OpInfo;
