358 void llvm::scaleProfData(Instruction &I, uint64_t S, uint64_t T) {
359   assert(T != 0 && "Caller should guarantee");
360   auto *ProfileData = I.getMetadata(LLVMContext::MD_prof);
361   if (ProfileData == nullptr)
362     return;
363 
364   auto *ProfDataName = dyn_cast<MDString>(ProfileData->getOperand(0));
365   if (!ProfDataName ||
366       (ProfDataName->getString() != MDProfLabels::BranchWeights &&
367        ProfDataName->getString() != MDProfLabels::ValueProfile))
368     return;
369 
370   if (!hasCountTypeMD(I))
371     return;
372 
373   LLVMContext &C = I.getContext();
374 
375   MDBuilder MDB(C);
376   SmallVector<Metadata *, 3> Vals;
377   Vals.push_back(ProfileData->getOperand(0));
378   APInt APS(128, S), APT(128, T);
379   if (ProfDataName->getString() == MDProfLabels::BranchWeights &&
380       ProfileData->getNumOperands() > 0) {
381     // Using APInt::div may be expensive, but most cases should fit 64 bits.
382     APInt Val(128,
383               mdconst::dyn_extract<ConstantInt>(
384                   ProfileData->getOperand(getBranchWeightOffset(ProfileData)))
385                   ->getValue()
386                   .getZExtValue());
387     Val *= APS;
388     Vals.push_back(MDB.createConstant(ConstantInt::get(
389         Type::getInt32Ty(C), Val.udiv(APT).getLimitedValue(UINT32_MAX))));
390   } else if (ProfDataName->getString() == MDProfLabels::ValueProfile)
391     for (unsigned Idx = 1; Idx < ProfileData->getNumOperands(); Idx += 2) {
392       // The first value is the key of the value profile, which will not change.
393       Vals.push_back(ProfileData->getOperand(Idx));
394       uint64_t Count =
395           mdconst::dyn_extract<ConstantInt>(ProfileData->getOperand(Idx + 1))
396               ->getValue()
397               .getZExtValue();
398       // Don't scale the magic number.
399       if (Count == NOMORE_ICP_MAGICNUM) {
400         Vals.push_back(ProfileData->getOperand(Idx + 1));
401         continue;
402       }
403       // Using APInt::div may be expensive, but most cases should fit 64 bits.
404       APInt Val(128, Count);
405       Val *= APS;
406       Vals.push_back(MDB.createConstant(ConstantInt::get(
407           Type::getInt64Ty(C), Val.udiv(APT).getLimitedValue())));
408     }
409   I.setMetadata(LLVMContext::MD_prof, MDNode::get(C, Vals));
410 }
